// Import all SVG icons
import ClearDay from './clear-day.svg';
import ClearNight from './clear-night.svg';
import PartlyCloudyDay from './partly-cloudy-day.svg';
import PartlyCloudyNight from './partly-cloudy-night.svg';
import Cloudy from './cloudy.svg';
import Rain from './rain.svg';
import Thunderstorm from './thunderstorm.svg';
import Snow from './snow.svg';
import Mist from './mist.svg';

// Map weather codes to SVG components
export const weatherIcons = {
  // Clear
  '01d': ClearDay,
  '01n': ClearNight,

  // Few clouds
  '02d': PartlyCloudyDay,
  '02n': PartlyCloudyNight,

  // Scattered clouds
  '03d': Cloudy,
  '03n': Cloudy,

  // Broken clouds
  '04d': Cloudy,
  '04n': Cloudy,

  // Shower rain
  '09d': Rain,
  '09n': Rain,

  // Rain
  '10d': Rain,
  '10n': Rain,

  // Thunderstorm
  '11d': Thunderstorm,
  '11n': Thunderstorm,

  // Snow
  '13d': Snow,
  '13n': Snow,

  // Mist
  '50d': Mist,
  '50n': Mist,
} as const;
